using System;
using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyPropertyEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext context)
        => UITypeEditorEditStyle.DropDown;

    public override object EditValue(ITypeDescriptorContext context, IServiceProvider provider, object value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService is null)
            return value;

        var control = CreateDropDownControl(value);

        // .NET 9 breaking change: DropDownControl(null) now throws ArgumentNullException.
        // Guard against null before calling.
        if (control is not null)
        {
            editorService.DropDownControl(control);
            value = GetControlValue(control) ?? value;
        }

        return value;
    }

    private static Control CreateDropDownControl(object currentValue)
    {
        if (currentValue is not string s)
            return null;

        var listBox = new ListBox();
        listBox.Items.Add(s);
        return listBox;
    }

    private static object GetControlValue(Control control)
    {
        if (control is ListBox lb && lb.SelectedItem is not null)
            return lb.SelectedItem;
        return null;
    }
}

using System;
using System.Runtime.InteropServices;

// .NET 9: Migrated from DllImport to LibraryImport for better
// AOT compatibility and trimming support.
